// Auto-generated — 1timoteo (NVI)
// Do NOT edit manually. Re-run scripts/download-bible.mjs to update.

export const BOOK_1TIMOTEO_NVI: Record<number, string[]> = {
  1: ["Pablo, apóstol de Cristo Jesús por mandato de Dios nuestro Salvador y de Cristo Jesús nuestra esperanza,","a Timoteo, mi verdadero hijo en la fe: Que Dios el Padre y Cristo Jesús nuestro Señor te concedan gracia, misericordia y paz.","Al partir para Macedonia, te encargué que permanecieras en Éfeso y les ordenaras a algunos supuestos maestros que dejen de enseñar doctrinas falsas","y de prestar atención a leyendas y genealogías interminables. Esas cosas provocan controversias en vez de llevar adelante la obra de Dios que es por la fe.","Debes hacerlo así para que el amor brote de un corazón limpio, de una buena conciencia y de una fe sincera.","Algunos se han desviado de esa línea de conducta y se han enredado en discusiones inútiles.","Pretenden ser maestros de la ley, pero en realidad no saben de qué hablan ni entienden lo que con tanta seguridad afirman.","Ahora bien, sabemos que la ley es buena, si se aplica como es debido.","Tengamos en cuenta que la ley no se ha instituido para los justos, sino para los desobedientes y rebeldes, para los impíos y pecadores, para los irreverentes y profanos. La ley es para los que maltratan a sus propios padres,[1] para los asesinos,","para los adúlteros y los homosexuales, para los traficantes de esclavos, los embusteros y los que juran en falso. En fin, la ley es para todo lo que está en contra de la sana doctrina","enseñada por el glorioso evangelio que el Dios bendito me ha confiado.","Doy gracias al que me fortalece, Cristo Jesús nuestro Señor, pues me consideró digno de confianza al ponerme a su servicio.","Anteriormente, yo era un blasfemo, un perseguidor y un insolente; pero Dios tuvo misericordia de mí porque yo era un incrédulo y actuaba con ignorancia.","Pero la gracia de nuestro Señor se derramó sobre mí con abundancia, junto con la fe y el amor que hay en Cristo Jesús.","Este mensaje es digno de crédito y merece ser aceptado por todos: que Cristo Jesús vino al mundo a salvar a los pecadores, de los cuales yo soy el primero.","Pero precisamente por eso Dios fue misericordioso conmigo, a fin de que en mí, el peor de los pecadores, pudiera Cristo Jesús mostrar su infinita bondad. Así llego a servir de ejemplo para los que, creyendo en él, recibirán la vida eterna.","Por tanto, al Rey eterno, inmortal, invisible, al único Dios, sea honor y gloria por los siglos de los siglos. Amén.","Timoteo, hijo mío, te doy este encargo porque tengo en cuenta las profecías que antes se hicieron acerca de ti. Deseo que, apoyado en ellas, pelees la buena batalla","y mantengas la fe y una buena conciencia. Por no hacerle caso a su conciencia, algunos han naufragado en la fe.","Entre ellos están Himeneo y Alejandro, a quienes he entregado a Satanás para que aprendan a no blasfemar."],
  2: ["Así que recomiendo, ante todo, que se hagan plegarias, oraciones, súplicas y acciones de gracias por todos,","especialmente por los gobernantes[2] y por todas las autoridades, para que tengamos paz y tranquilidad, y llevemos una vida piadosa y digna.","Esto es bueno y agradable a Dios nuestro Salvador,","pues él quiere que todos sean salvos y lleguen a conocer la verdad.","Porque hay un solo Dios y un solo mediador entre Dios y los hombres, Jesucristo hombre,","quien dio su vida como rescate por todos. Este testimonio Dios lo ha dado a su debido tiempo,","y para proclamarlo me nombró heraldo y apóstol. Digo la verdad y no miento: Dios me hizo maestro de los gentiles para enseñarles la verdadera fe.","Quiero, pues, que en todas partes los hombres oren, levantando las manos al cielo con pureza de corazón, sin enojos ni contiendas.","En cuanto a las mujeres, quiero que ellas se vistan decorosamente, con modestia y recato, sin peinados ostentosos, ni oro, ni perlas ni vestidos costosos.","Que se adornen más bien con buenas obras, como corresponde a mujeres que profesan servir a Dios.","La mujer debe aprender con serenidad,[3] con toda sumisión.","No permito que la mujer enseñe al hombre y ejerza autoridad sobre él; debe mantenerse ecuánime.[4]","Porque primero fue formado Adán, y Eva después.","Además, no fue Adán el engañado, sino la mujer; y ella, una vez engañada, incurrió en pecado.","Pero la mujer se salvará[5] siendo madre y permaneciendo con sensatez en la fe, el amor y la santidad."],
  3: ["Se dice, y es verdad, que, si alguno desea ser obispo, a noble función aspira.","Así que el obispo debe ser intachable, esposo de una sola mujer, moderado, sensato, respetable, hospitalario, capaz de enseñar;","no debe ser borracho ni pendenciero, ni amigo del dinero, sino amable y apacible.","Debe gobernar bien su casa y hacer que sus hijos le obedezcan con el debido respeto;","porque el que no sabe gobernar su propia familia, ¿cómo podrá cuidar de la iglesia de Dios?","No debe ser un recién convertido, no sea que se vuelva presuntuoso y caiga en la misma condenación en que cayó el diablo.","Se requiere además que hablen bien de él los que no pertenecen a la iglesia,[6] para que no caiga en descrédito y en la trampa del diablo.","Los diáconos, igualmente, deben ser honorables, sinceros, no amigos del mucho vino ni codiciosos de las ganancias mal habidas.","Deben guardar, con una conciencia limpia, las grandes verdades[7] de la fe.","Que primero sean puestos a prueba, y después, si no hay nada que reprocharles, que sirvan como diáconos.","Así mismo, las esposas de los diáconos[8] deben ser honorables, no calumniadoras, sino moderadas y dignas de toda confianza.","El diácono debe ser esposo de una sola mujer y gobernar bien a sus hijos y su propia casa.","Los que ejercen bien el diaconado se ganan un lugar de honor y adquieren mayor confianza para hablar de su fe en Cristo Jesús.","Aunque espero ir pronto a verte, escribo estas instrucciones para que,","si me retraso, sepas cómo hay que portarse en la casa de Dios, que es la iglesia del Dios viviente, columna y fundamento de la verdad.","No hay duda de que es grande el misterio de nuestra fe:[9] Él[10] se manifestó como hombre;[11] fue vindicado por[12] el Espíritu, visto por los ángeles, proclamado entre las naciones, creído en el mundo, recibido en la gloria."],
  4: ["El Espíritu dice claramente que, en los últimos tiempos, algunos abandonarán la fe para seguir a inspiraciones engañosas y doctrinas diabólicas.","Tales enseñanzas provienen de embusteros hipócritas, que tienen la conciencia encallecida.[13]","Prohíben el matrimonio y no permiten comer ciertos alimentos que Dios ha creado para que los creyentes,[14] conocedores de la verdad, los coman con acción de gracias.","Todo lo que Dios ha creado es bueno, y nada es despreciable si se recibe con acción de gracias,","porque la palabra de Dios y la oración lo santifican.","Si enseñas estas cosas a los hermanos, serás un buen servidor de Cristo Jesús, nutrido con las verdades de la fe y de la buena enseñanza que paso a paso has seguido.","Rechaza las leyendas profanas y otros mitos semejantes.[15] Más bien, ejercítate en la piedad,","pues aunque el ejercicio físico trae algún provecho, la piedad es útil para todo, ya que incluye una promesa no solo para la vida presente, sino también para la venidera.","Este mensaje es digno de crédito y merece ser aceptado por todos.","En efecto, si trabajamos y nos esforzamos es porque hemos puesto nuestra esperanza en el Dios viviente, que es el Salvador de todos, especialmente de los que creen.","Encarga y enseña estas cosas.","Que nadie te menosprecie por ser joven. Al contrario, que los creyentes vean en ti un ejemplo a seguir en la manera de hablar, en la conducta, y en amor, fe y pureza.","En tanto que llego, dedícate a la lectura pública de las Escrituras, y a enseñar y animar a los hermanos.","Ejercita el don que recibiste mediante profecía, cuando los ancianos te impusieron las manos.","Sé diligente en estos asuntos; entrégate de lleno a ellos, de modo que todos puedan ver que estás progresando.","Ten cuidado de tu conducta y de tu enseñanza. Persevera en todo ello, porque así te salvarás a ti mismo y a los que te escuchen."],
  5: ["No reprendas con dureza al anciano, sino aconséjalo como si fuera tu padre. Trata a los jóvenes como a hermanos;","a las ancianas, como a madres; a las jóvenes, como a hermanas, con toda pureza.","Reconoce debidamente a las viudas que de veras están desamparadas.","Pero, si una viuda tiene hijos o nietos, que estos aprendan primero a cumplir sus obligaciones con su propia familia y correspondan así a sus padres y abuelos, porque eso agrada a Dios.","La viuda desamparada, como ha quedado sola, pone su esperanza en Dios y persevera noche y día en sus oraciones y súplicas.","En cambio, la viuda que se entrega al placer ya está muerta en vida.","Encárgales estas cosas para que sean intachables.","El que no provee para los suyos, y sobre todo para los de su propia casa, ha negado la fe y es peor que un incrédulo.","En la lista de las viudas debe figurar únicamente la que tenga más de sesenta años, que haya sido fiel a su esposo,[16]","y que sea reconocida por sus buenas obras, tales como criar hijos, practicar la hospitalidad, lavar los pies de los creyentes, ayudar a los que sufren y aprovechar toda oportunidad para hacer el bien.","No incluyas en esa lista a las viudas más jóvenes, porque cuando sus pasiones las alejan de Cristo, les da por casarse.","Así resultan culpables de faltar a su primer compromiso.","Además se acostumbran a estar ociosas y andar de casa en casa. Y no solo se vuelven holgazanas, sino también chismosas y entrometidas, hablando de lo que no deben.","Por eso exhorto a las viudas jóvenes a que se casen y tengan hijos, y a que lleven bien su hogar y no den lugar a las críticas del enemigo.","Y es que algunas ya se han descarriado para seguir a Satanás.","Si alguna creyente tiene viudas en su familia, debe ayudarlas para que no sean una carga a la iglesia; así la iglesia podrá atender a las viudas desamparadas.","Los ancianos que dirigen bien los asuntos de la iglesia son dignos de doble honor,[17] especialmente los que dedican sus esfuerzos a la predicación y a la enseñanza.","Pues la Escritura dice: «No le pongas bozal al buey mientras esté trillando»,[18] y «El trabajador merece que se le pague su salario».[19]","No admitas ninguna acusación contra un anciano, a no ser que esté respaldada por dos o tres testigos.","A los que pecan, repréndelos en público para que sirva de escarmiento.","Te insto delante de Dios, de Cristo Jesús y de los santos ángeles a que sigas estas instrucciones sin dejarte llevar de prejuicios ni favoritismos.","No te apresures a imponerle las manos a nadie, no sea que te hagas cómplice de pecados ajenos. Consérvate puro.","No sigas bebiendo solo agua; toma también un poco de vino a causa de tu mal de estómago y tus frecuentes enfermedades.","Los pecados de algunos son evidentes aun antes de ser investigados, mientras que los pecados de otros se descubren después.","De igual manera son evidentes las buenas obras y, aunque estén ocultas, tarde o temprano se manifestarán.[20]"],
  6: ["Todos los que aún son esclavos deben reconocer que sus amos merecen todo respeto; así evitarán que se hable mal del nombre de Dios y de nuestra enseñanza.","Los que tienen amos creyentes no deben faltarles al respeto por ser hermanos. Al contrario, deben servirles todavía mejor, porque los que se benefician de sus servicios son creyentes y hermanos queridos. Esto es lo que debes enseñar y recomendar.","Si alguien enseña falsas doctrinas, apartándose de la sana enseñanza de nuestro Señor Jesucristo y de la doctrina que se ciñe a la verdadera religión,[21]","es un obstinado que nada entiende. Ese tal padece del afán enfermizo de provocar discusiones inútiles que generan envidias, discordias, insultos, suspicacias","y altercados entre personas de mente depravada, carentes de la verdad. Este es de los que piensan que la religión es un medio de obtener ganancias.","Es cierto que con la verdadera religión se obtienen grandes ganancias, pero solo si uno está satisfecho con lo que tiene.","Porque nada trajimos a este mundo, y nada podemos llevarnos.","Así que, si tenemos ropa y comida, contentémonos con eso.","Los que quieren enriquecerse caen en la tentación y se vuelven esclavos de sus muchos deseos. Estos afanes insensatos y dañinos hunden a la gente en la ruina y en la destrucción.","Porque el amor al dinero es la raíz de toda clase de males. Por codiciarlo, algunos se han desviado de la fe y se han causado muchísimos sinsabores.","Tú, en cambio, hombre de Dios, huye de todo eso, y esmérate en seguir la justicia, la piedad, la fe, el amor, la constancia y la humildad.","Pelea la buena batalla de la fe; haz tuya la vida eterna, a la que fuiste llamado y por la cual hiciste aquella admirable declaración de fe delante de muchos testigos.","Teniendo a Dios por testigo, el cual da vida a todas las cosas, y a Cristo Jesús, que dio su admirable testimonio delante de Poncio Pilato, te encargo","que guardes este mandato sin mancha ni reproche hasta la venida de nuestro Señor Jesucristo,","la cual Dios a su debido tiempo hará que se cumpla. Al único y bendito Soberano, Rey de reyes y Señor de señores,","al único inmortal, que vive en luz inaccesible, a quien nadie ha visto ni puede ver, a él sea el honor y el poder eternamente. Amén.","A los ricos de este mundo, mándales que no sean arrogantes ni pongan su esperanza en las riquezas, que son tan inseguras, sino en Dios, que nos provee de todo en abundancia para que lo disfrutemos.","Mándales que hagan el bien, que sean ricos en buenas obras, y generosos, dispuestos a compartir lo que tienen.","De este modo atesorarán para sí un seguro caudal para el futuro y obtendrán la vida verdadera.","Timoteo, ¡cuida bien lo que se te ha confiado! Evita las discusiones profanas e inútiles, y los argumentos de la falsa ciencia.","Algunos, por abrazarla, se han desviado de la fe. Que la gracia sea con ustedes."],
};
